// PostQuery* family for read-only operations that ride a mutating verb on
// the wire (GraphQL queries, JSON-RPC reads, POST-based search endpoints).
// The wire verb is still POST/PUT/PATCH so the server sees a real request,
// but the verify-mode short-circuit does not fire because the operation
// does not mutate remote state.
func (c *Client) doRead(ctx context.Context, method, path string, params map[string]string, body any, headerOverrides map[string]string) (json.RawMessage, int, error) {
	return c.doInternal(ctx, method, path, params, body, headerOverrides, true)
}

// doInternal is the shared implementation behind do() and doRead(). The
// readOnlyIntent flag is set by doRead() callers (read-only POST/PUT/PATCH
// operations like GraphQL queries) to skip the mutating-verb verify-mode
// gate. Plain do() callers leave it false and get the usual short-circuit.
func (c *Client) doInternal(ctx context.Context, method, path string, params map[string]string, body any, headerOverrides map[string]string, readOnlyIntent bool) (json.RawMessage, int, error) {
	// Verify-mode transport-layer gate. When the verifier (or any consumer
	// that sets PRINTING_PRESS_VERIFY=1) drives a mutating verb without
	// the LIVE_HTTP=1 opt-in, return a synthetic envelope without dialing,
	// minting auth, or touching the cache. The verify pipeline itself
	// sets both env vars in mock mode so its httptest server still sees
	// real requests; every other consumer gets a safe no-op.
	//
	// readOnlyIntent suppresses the gate for read-only operations that
	// happen to ride a mutating verb on the wire (GraphQL queries, JSON-RPC
	// reads, POST-based search endpoints). The handler-level annotation
	// `mcp:read-only: true` drives the codegen choice of doRead() vs do().
	//
	// Placement note: this fires BEFORE URL building, auth header
	// minting, and the success-branch invalidateCache() call below — so
	// no cache invalidation runs (no remote state changed) and no
	// client_credentials mint happens unnecessarily.
	if !readOnlyIntent && isMutatingVerb(method) && cliutil.IsVerifyEnv() && !cliutil.IsVerifyLiveHTTPEnv() {
		return verifyShortCircuitEnvelope(method, path), http.StatusOK, nil
	}
	// An absolute URL (http:// or https://) bypasses BaseURL — needed for hybrid
	// surfaces where some endpoints live on a different host (e.g. X Articles
	// GraphQL on x.com and media upload on upload.x.com while v2 is on api.x.com).
	// Only allow absolute URLs for the X surface this CLI is built for; refusing
	// arbitrary hosts prevents accidental token exfiltration if a caller path
	// becomes user-controllable.
	var targetURL string
	if strings.HasPrefix(path, "http://") || strings.HasPrefix(path, "https://") {
		if !isAllowedAbsoluteHost(hostFromURL(path)) {
			return nil, 0, fmt.Errorf("absolute URL not allowed: host %q is not in the x.com/api.x.com/upload.x.com allowlist", hostFromURL(path))
		}
		targetURL = path
	} else {
		targetURL = c.BaseURL + path
	}

	var bodyBytes []byte
	if body != nil {
		b, err := json.Marshal(body)
		if err != nil {
			return nil, 0, fmt.Errorf("marshaling body: %w", err)
		}
		bodyBytes = b
	}

	// Resolve auth material before the dry-run branch so --dry-run can preview
	// exactly what would be sent. Uses only cached credentials; a token that
	// requires a network refresh will be re-fetched on the live request path,
	// not during dry-run.
	//
	// Resolve OAuth (Source A) auth material only when the target host actually
	// uses it. Cookie-auth hosts (x.com / upload.x.com — Source B) skip OAuth
	// resolution so a missing/expired OAuth token does not block Articles or
	// media-upload calls; their auth is injected per-request below via
	// cookies.apply().
	var authHeader string
	if overrideAuth := authorizationHeaderOverride(headerOverrides); overrideAuth != "" {
		authHeader = overrideAuth
	} else if !hostUsesCookieAuth(hostFromURL(targetURL)) {
		h, err := c.authHeader(ctx)
		if err != nil {
			return nil, 0, err
		}
		authHeader = h
	}

	// Build the request for dry-run display or actual execution
	if c.DryRun {
		return c.dryRun(method, targetURL, path, params, bodyBytes, headerOverrides, authHeader)
	}

	const maxRetries = 3
	var lastErr error
	refreshedAfterUnauthorized := false
	retriedAsAppOnly := false

	for attempt := 0; attempt <= maxRetries; attempt++ {
		// Proactive rate limiting — wait before sending
		c.limiter.Wait()
		var bodyReader io.Reader
		if bodyBytes != nil {
			bodyReader = strings.NewReader(string(bodyBytes))
		}

		req, err := http.NewRequestWithContext(ctx, method, targetURL, bodyReader)
		if err != nil {
			return nil, 0, fmt.Errorf("creating request: %w", err)
		}
		if bodyBytes != nil {
			req.Header.Set("Content-Type", "application/json")
		}

		if params != nil {
			q := req.URL.Query()
			for k, v := range params {
				if v != "" {
					q.Set(k, v)
				}
			}
			req.URL.RawQuery = q.Encode()
		}

		// Per-host auth selector. Hosts on x.com / upload.x.com use the
		// browser-session cookie auth captured at sniff time (Source B). All
		// other hosts (api.x.com etc.) use the OAuth 2.0 bearer (Source A).
		if hostUsesCookieAuth(req.URL.Host) {
			cookies, err := LoadCookieAuth()
			if err != nil {
				return nil, 0, fmt.Errorf("cookie auth required for %s: %w", req.URL.Host, err)
			}
			cookies.apply(req)
		} else if authHeader != "" {
			req.Header.Set("Authorization", authHeader)
		}
		if c.Config != nil {
			for k, v := range c.Config.Headers {
				req.Header.Set(k, v)
			}
		}
		// Per-endpoint header overrides (e.g., different API version per resource)
		for k, v := range headerOverrides {
			if strings.EqualFold(k, "Authorization") && authHeader != "" && v != authHeader {
				continue
			}
			req.Header.Set(k, v)
		}
		binaryResponse := strings.EqualFold(req.Header.Get(BinaryResponseHeader), "true")
		if binaryResponse {
			req.Header.Del(BinaryResponseHeader)
		}
		if req.Header.Get("User-Agent") == "" {
			req.Header.Set("User-Agent", "x-twitter-pp-cli/2.165")
		}
		// Go's net/http omits Accept by default; browsers, curl, and other
		// stdlibs always send it. Fingerprint-checking WAFs (Imperva, Akamai,
		// Cloudflare bot-mode, DataDome) flag the absence as a bot signal
		// and answer with empty-body 5xx, 403, or a challenge redirect
		// depending on vendor and rule tier. The value is application/json
		// rather than */* because strict-JSON APIs (Zendesk, Atlassian REST,
		// Salesforce) return 415 on anything that isn't literally
		// application/json; specs that need a different content type
		// (vendor mediatypes, XML, HTML) declare it via RequiredHeaders or
		// per-endpoint headerOverrides, both of which run before this
		// if-empty default.
		if req.Header.Get("Accept") == "" {
			if binaryResponse {
				req.Header.Set("Accept", "*/*")
			} else {
				req.Header.Set("Accept", "application/json")
			}
		}

		resp, err := c.HTTPClient.Do(req)
		if err != nil {
			if ctxErr := ctx.Err(); ctxErr != nil {
				return nil, 0, ctxErr
			}
			lastErr = fmt.Errorf("%s %s: %w", method, c.displayURL(path, authHeader), c.maskError(err, authHeader))
			continue
		}

		respBody, err := io.ReadAll(resp.Body)
		resp.Body.Close()
		if err != nil {
			return nil, 0, fmt.Errorf("reading response: %w", err)
		}

		// Success
		if resp.StatusCode < 400 {
			c.limiter.OnSuccess()
			if method != http.MethodGet && !c.DryRun {
				c.invalidateCache()
			}
			// Non-textual bodies (PDF, zip, image, octet-stream) must not be
			// run through the JSON sanitizer or returned as raw json.RawMessage
			// — return a self-describing base64 envelope instead. Textual and
			// JSON responses fall through to the unchanged path.
			if isBinaryResponseContentType(resp.Header.Get("Content-Type")) {
				env, encErr := wrapBinaryResponse(resp.Header.Get("Content-Type"), respBody)
				if encErr != nil {
					return nil, 0, encErr
				}
				return env, resp.StatusCode, nil
			}
			return json.RawMessage(sanitizeJSONResponse(respBody)), resp.StatusCode, nil
		}

		if !binaryResponse {
			respBody = sanitizeJSONResponse(respBody)
		}

		apiErr := &APIError{
			Method:     method,
			Path:       c.displayURL(path, authHeader),
			StatusCode: resp.StatusCode,
			Body:       c.maskCredentialText(truncateBody(respBody), authHeader),
		}

		if resp.StatusCode == http.StatusUnauthorized && !refreshedAfterUnauthorized && authorizationHeaderOverride(headerOverrides) == "" && !hostUsesCookieAuth(req.URL.Host) {
			refreshed, refreshErr := c.RefreshOAuth2UserContext(ctx, true)
			if refreshErr == nil && refreshed {
				// The forced refresh above already exchanged and persisted the token.
				// Read the current header directly so the retry does not perform a
				// second proactive refresh before sending the recovered request.
				if h, err := c.currentAuthHeader(); err == nil && h != "" {
					authHeader = h
					refreshedAfterUnauthorized = true
					lastErr = apiErr
					continue
				}
			}
		}

		// App-only fallback: when OAuth2 user-context token is expired/stale
		// and refresh was unavailable or failed, retry public v2 reads with
		// the app-only Bearer token. Only fires when both credentials exist
		// so single-credential setups are unaffected. User-context-only
		// endpoints (e.g. /2/users/me) will return 403 Unsupported Authentication
		// on retry — the existing classifyAPIError handler converts that to a
		// better error hint than the original 401.
		if resp.StatusCode == http.StatusUnauthorized && !retriedAsAppOnly && authorizationHeaderOverride(headerOverrides) == "" && !hostUsesCookieAuth(req.URL.Host) && c.Config != nil && c.Config.XOauth2UserToken != "" && c.Config.XBearerToken != "" {
			authHeader = "Bearer " + c.Config.XBearerToken
			retriedAsAppOnly = true
			lastErr = apiErr
			continue
		}

		// Rate limited - adjust adaptive limiter and retry
		if resp.StatusCode == 429 && attempt < maxRetries {
			c.limiter.OnRateLimit()
			wait := cliutil.RetryAfter(resp)
			fmt.Fprintf(os.Stderr, "rate limited, waiting %s (attempt %d/%d, rate adjusted to %.1f req/s)\n", wait, attempt+1, maxRetries, c.limiter.Rate())
			if err := sleepContext(ctx, wait); err != nil {
				return nil, 0, err
			}
			lastErr = apiErr
			continue
		}

		// Server error - retry with backoff
		if resp.StatusCode >= 500 && attempt < maxRetries {
			wait := time.Duration(math.Pow(2, float64(attempt))) * time.Second
			fmt.Fprintf(os.Stderr, "server error %d, retrying in %s (attempt %d/%d)\n", resp.StatusCode, wait, attempt+1, maxRetries)
			if err := sleepContext(ctx, wait); err != nil {
				return nil, 0, err
			}
			lastErr = apiErr
			continue
		}

		// Client error or retries exhausted - return the error
		return nil, resp.StatusCode, apiErr
	}

	return nil, 0, lastErr
}

// dryRun prints the outgoing request exactly as the live path would send it,
// using the auth material already resolved in `do()`. Never triggers a network
// call — the caller is responsible for passing cached auth material only.
func (c *Client) dryRun(method, targetURL, path string, params map[string]string, body []byte, headerOverrides map[string]string, authHeader string) (json.RawMessage, int, error) {
	fmt.Fprintf(os.Stderr, "%s %s\n", method, c.displayURL(targetURL, authHeader))
	queryPrinted := false
	if params != nil {
		keys := make([]string, 0, len(params))
		for k := range params {
			if params[k] != "" {
				keys = append(keys, k)
			}
		}
		sort.Strings(keys)
		for _, k := range keys {
			sep := "?"
			if queryPrinted {
				sep = "&"
			}
			fmt.Fprintf(os.Stderr, "  %s%s=%s\n", sep, k, c.maskCredentialText(params[k], authHeader))
			queryPrinted = true
		}
	}
	_ = queryPrinted
	var bodyValue any
	if body != nil {
		var pretty json.RawMessage
		if json.Unmarshal(body, &bodyValue) == nil {
			redacted, _ := json.Marshal(c.redactDryRunBodyValue(bodyValue))
			pretty = json.RawMessage(redacted)
			enc := json.NewEncoder(os.Stderr)
			enc.SetIndent("  ", "  ")
			fmt.Fprintf(os.Stderr, "  Body:\n")
			enc.Encode(pretty)
		}
	}
	if authHeader != "" {
		fmt.Fprintf(os.Stderr, "  %s: %s\n", "Authorization", maskToken(authHeader))
	}
	fmt.Fprintf(os.Stderr, "\n(dry run - no request sent)\n")
	envelope := map[string]any{
		"dry_run": true,
		"sent":    false,
		"request": map[string]any{
			"method": method,
			"path":   path,
		},
		"meta": map[string]any{
			"auth_lane":        c.dryRunAuthLane(targetURL, authHeader),
			"selected_profile": c.selectedProfile(),
		},
	}
	if params != nil {
		cleanParams := map[string]string{}
		for k, v := range params {
			if v != "" {
				cleanParams[k] = c.maskCredentialText(v, authHeader)
			}
		}
		if len(cleanParams) > 0 {
			envelope["request"].(map[string]any)["params"] = cleanParams
		}
	}
	if bodyValue != nil {
		envelope["request"].(map[string]any)["body"] = c.redactDryRunBodyValue(bodyValue)
	}
	if action := inferXPublicAction(method, path, bodyValue); action != "" {
		envelope["public_action"] = action
	}
	if isMutatingVerb(method) {
		envelope["mutation"] = true
	}
	data, err := json.Marshal(envelope)
	if err != nil {
		return nil, 0, err
	}
	return json.RawMessage(data), 0, nil
}

func (c *Client) selectedProfile() string {
	if c != nil && c.Config != nil && c.Config.SelectedProfile != "" {
		return c.Config.SelectedProfile
	}
	return "default"
}

func (c *Client) dryRunAuthLane(targetURL, authHeader string) string {
	if hostUsesCookieAuth(hostFromURL(targetURL)) {
		return "x_articles_cookie"
	}
	if c == nil || c.Config == nil || authHeader == "" {
		return "none"
	}
	switch authHeader {
	case c.Config.UserContextAuthHeader():
		return "oauth2_user_context"
	case c.Config.AppOnlyAuthHeader():
		return "app_only_api"
	default:
		return "custom"
	}
}

func inferXPublicAction(method, path string, body any) string {
	switch {
	case method == http.MethodPost && path == "/2/tweets":
		bodyMap, _ := body.(map[string]any)
		if _, ok := bodyMap["quote_tweet_id"]; ok {
			return "quote"
		}
		if _, ok := bodyMap["reply"]; ok {
			return "reply"
		}
		return "post"
	case method == http.MethodDelete && strings.HasPrefix(path, "/2/tweets/"):
		return "delete_post"
	case method == http.MethodPost && strings.Contains(path, "/likes"):
		return "like"
	case method == http.MethodDelete && strings.Contains(path, "/likes/"):
		return "unlike"
	case method == http.MethodPost && strings.Contains(path, "/retweets"):
		return "repost"
	case method == http.MethodDelete && strings.Contains(path, "/retweets/"):
		return "unrepost"
	case method == http.MethodPost && strings.Contains(path, "/following"):
		return "follow"
	case method == http.MethodDelete && strings.Contains(path, "/following/"):
		return "unfollow"
	case method == http.MethodPost && strings.Contains(path, "/dm_"):
		return "dm"
	}
	return ""
}

func (c *Client) redactDryRunBodyValue(value any) any {
	switch typed := value.(type) {
	case map[string]any:
		out := make(map[string]any, len(typed))
		for k, v := range typed {
			if dryRunSecretBodyKey(k) {
				out[k] = "[REDACTED]"
				continue
			}
			out[k] = c.redactDryRunBodyValue(v)
		}
		return out
	case []any:
		out := make([]any, len(typed))
		for i, v := range typed {
			out[i] = c.redactDryRunBodyValue(v)
		}
		return out
	case string:
		return c.maskCredentialText(typed)
	default:
		return value
	}
}

func dryRunSecretBodyKey(key string) bool {
	normalized := strings.ToLower(strings.TrimSpace(key))
	normalized = strings.ReplaceAll(normalized, "-", "_")
	for _, marker := range []string{"authorization", "cookie", "token", "secret", "password"} {
		if strings.Contains(normalized, marker) {
			return true
		}
	}
	return false
}

func (c *Client) ConfiguredTimeout() time.Duration {
	if c.HTTPClient != nil && c.HTTPClient.Timeout > 0 {
		return c.HTTPClient.Timeout
	}
	return 60 * time.Second
}

func (c *Client) authHeader(ctx context.Context) (string, error) {
	if c.Config == nil {
		return "", nil
	}
	if _, err := c.RefreshOAuth2UserContext(ctx, false); err != nil {
		// Proactive refresh is best-effort. If the token endpoint is briefly
		// unavailable, keep the current access token on the wire and let the
		// normal 401 path decide whether a forced refresh is actually required.
		// This avoids turning a likely-successful near-expiry request into an
		// immediate local failure.
		return c.currentAuthHeader()
	}
	return c.currentAuthHeader()
}

func (c *Client) currentAuthHeader() (string, error) {
	if c == nil || c.Config == nil {
		return "", nil
	}
	authHeader := c.Config.AuthHeader()
	if authHeaderLooksLikePlaceholderCredential(authHeader) {
		return "", authPlaceholderCredentialError(c.Config)
	}
	return authHeader, nil
}

func (c *Client) RefreshOAuth2UserContext(ctx context.Context, force bool) (bool, error) {
	if c == nil || c.Config == nil {
		return false, nil
	}
	c.refreshMu.Lock()
	defer c.refreshMu.Unlock()

	cfg := c.Config
	if strings.TrimSpace(cfg.RefreshToken) == "" || strings.TrimSpace(cfg.ClientID) == "" {
		return false, nil
	}
	if !force && (cfg.TokenExpiry.IsZero() || time.Until(cfg.TokenExpiry) > time.Minute) {
		return false, nil
	}
	form := url.Values{}
	form.Set("grant_type", "refresh_token")
	form.Set("refresh_token", strings.TrimSpace(cfg.RefreshToken))
	form.Set("client_id", strings.TrimSpace(cfg.ClientID))
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, OAuth2TokenEndpoint, strings.NewReader(form.Encode()))
	if err != nil {
		return false, err
	}
	req.Header.Set("Content-Type", "application/x-www-form-urlencoded")
	if strings.TrimSpace(cfg.ClientSecret) != "" {
		req.SetBasicAuth(strings.TrimSpace(cfg.ClientID), strings.TrimSpace(cfg.ClientSecret))
	}
	httpClient := c.HTTPClient
	if httpClient == nil {
		httpClient = http.DefaultClient
	}
	resp, err := httpClient.Do(req)
	if err != nil {
		return false, fmt.Errorf("refreshing OAuth2 user-context token: %w", err)
	}
	defer resp.Body.Close()
	body, _ := io.ReadAll(io.LimitReader(resp.Body, 64*1024))
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return false, fmt.Errorf("refreshing OAuth2 user-context token failed: HTTP %d: %s", resp.StatusCode, strings.TrimSpace(string(body)))
	}
	var token struct {
		TokenType    string `json:"token_type"`
		ExpiresIn    int    `json:"expires_in"`
		AccessToken  string `json:"access_token"`
		RefreshToken string `json:"refresh_token"`
		Scope        string `json:"scope"`
	}
	if err := json.Unmarshal(body, &token); err != nil {
		return false, fmt.Errorf("parsing OAuth2 refresh response: %w", err)
	}
	accessToken := strings.TrimSpace(token.AccessToken)
	if accessToken == "" {
		return false, fmt.Errorf("OAuth2 refresh response did not include access_token")
	}
	refreshToken := strings.TrimSpace(token.RefreshToken)
	if refreshToken == "" {
		refreshToken = strings.TrimSpace(cfg.RefreshToken)
	}
	expiry := time.Time{}
	if token.ExpiresIn > 0 {
		expiry = time.Now().UTC().Add(time.Duration(token.ExpiresIn) * time.Second)
	}
	scopes := cfg.Scopes
	if strings.TrimSpace(token.Scope) != "" {
		scopes = strings.Fields(strings.ReplaceAll(token.Scope, ",", " "))
	}
	if err := cfg.SaveOAuth2UserContext(cfg.ClientID, cfg.ClientSecret, accessToken, refreshToken, expiry, scopes); err != nil {
		return false, fmt.Errorf("saving refreshed OAuth2 user-context token: %w", err)
	}
	return true, nil
}

func authHeaderLooksLikePlaceholderCredential(header string) bool {
	if scheme, encoded, ok := strings.Cut(strings.TrimSpace(header), " "); ok && strings.EqualFold(scheme, "Basic") {
		encoded = strings.TrimSpace(encoded)
		decoded, err := base64.StdEncoding.DecodeString(encoded)
		if err == nil && authHeaderLooksLikePlaceholderCredential(string(decoded)) {
			return true
		}
	}
	if !strings.Contains(header, "<") && !strings.Contains(header, "YOUR_TOKEN_HERE") && !strings.Contains(header, "your-token") && !strings.Contains(header, "your-key") {
		return false
	}
	for _, field := range strings.Fields(header) {
		field = strings.Trim(field, `"'`)
		if idx := strings.LastIndex(field, "="); idx >= 0 {
			field = field[idx+1:]
		}
		if idx := strings.Index(field, ":"); idx >= 0 {
			if looksLikeCredentialPlaceholder(field[:idx]) || looksLikeCredentialPlaceholder(field[idx+1:]) {
				return true
			}
		}
		if looksLikeCredentialPlaceholder(field) {
			return true
		}
	}
	return looksLikeCredentialPlaceholder(header)
}

func looksLikeCredentialPlaceholder(value string) bool {
	value = strings.Trim(strings.TrimSpace(value), `"'`)
	switch value {
	case "<your-token>", "<your-key>", "<paste-your-key>", "YOUR_TOKEN_HERE", "your-token-here":
		return true
	}
	if len(value) < 3 || value[0] != '<' || value[len(value)-1] != '>' {
		return false
	}
	for _, r := range value[1 : len(value)-1] {
		if r != '_' && (r < 'A' || r > 'Z') {
			return false
		}
	}
	return true
}

func authPlaceholderCredentialError(cfg *config.Config) error {
	return authPlaceholderCredentialErrorWithSetup(cfg, "export X_BEARER_TOKEN=<your-token> or x-twitter-pp-cli auth set-bearer-token <token>")
}

func authPlaceholderCredentialErrorWithSetup(cfg *config.Config, setup string) error {
	location := "config file"
	if cfg != nil && cfg.Path != "" {
		location = cfg.Path
	}
	return fmt.Errorf("%w configured in %s; set a real token with: %s", ErrPlaceholderCredential, location, setup)
}

// binaryResponseEnvelope wraps a non-textual success body so it survives the
// json.RawMessage contract every consumer (CLI output, --json, MCP tools)
// depends on. Without it, raw bytes (PDF, zip, image) are corrupted by
// sanitizeJSONResponse and emitted as invalid JSON. The _pp_binary
// discriminator lets callers and agents detect and base64-decode the payload.
type binaryResponseEnvelope struct {
	PPBinary    bool   `json:"_pp_binary"`
	ContentType string `json:"content_type"`
	Encoding    string `json:"encoding"`
	Bytes       int    `json:"bytes"`
	Data        string `json:"data"`
}

// isBinaryResponseContentType reports whether a successful response with this
// Content-Type must be base64-wrapped instead of treated as text/JSON. It is
// deliberately narrow: JSON, */*, XML, and every text/* type (including
// text/html, so response_format:html CLIs are untouched) pass through
// unchanged. Only genuinely binary payloads are wrapped.
func isBinaryResponseContentType(ct string) bool {
	mt := strings.ToLower(strings.TrimSpace(ct))
	if i := strings.IndexByte(mt, ';'); i >= 0 {
		mt = strings.TrimSpace(mt[:i])
	}
	if mt == "" {
		return false
	}
	switch {
	case mt == "application/json", mt == "text/json", mt == "*/*":
		return false
	case strings.HasPrefix(mt, "text/"):
		return false
	case strings.HasSuffix(mt, "+json"), strings.HasSuffix(mt, "+xml"):
		return false
	case mt == "application/xml", mt == "application/xhtml+xml":
		return false
	case mt == "application/javascript", mt == "application/ecmascript",
		mt == "application/x-www-form-urlencoded", mt == "application/graphql":
		return false
	}
	return true
}

// wrapBinaryResponse marshals body into a self-describing base64 envelope.
func wrapBinaryResponse(ct string, body []byte) (json.RawMessage, error) {
	out, err := json.Marshal(binaryResponseEnvelope{
		PPBinary:    true,
		ContentType: ct,
		Encoding:    "base64",
		Bytes:       len(body),
		Data:        base64.StdEncoding.EncodeToString(body),
	})
	if err != nil {
		return nil, fmt.Errorf("encoding binary response: %w", err)
	}
	return json.RawMessage(out), nil
}

// sanitizeJSONResponse strips known JSONP/XSSI prefixes and UTF-8 BOM from
// response bodies so that downstream JSON parsing succeeds. For clean JSON
// responses these checks are no-ops.
func sanitizeJSONResponse(body []byte) []byte {
	// UTF-8 BOM
	body = bytes.TrimPrefix(body, []byte("\xEF\xBB\xBF"))

	// JSONP/XSSI prefixes, ordered longest-first where prefixes overlap
	prefixes := [][]byte{
		[]byte(")]}'\n"),
		[]byte(")]}'"),
		[]byte("{}&&"),
		[]byte("for(;;);"),
		[]byte("while(1);"),
	}
	for _, p := range prefixes {
		if bytes.HasPrefix(body, p) {
			body = bytes.TrimPrefix(body, p)
			body = bytes.TrimLeft(body, " \t\r\n")
			break
		}
	}
	return body
}

// maskToken redacts all but the last 4 characters of a token for safe display.
func maskToken(token string) string {
	if token == "" {
		return ""
	}
	if len(token) <= 4 {
		return "****"
	}
	return "****" + token[len(token)-4:]
}

type maskedError struct {
	msg string
}

func (e maskedError) Error() string {
	return e.msg
}

func (c *Client) displayURL(rawURL string, extraCredentials ...string) string {
	return c.maskCredentialText(rawURL, extraCredentials...)
}

func (c *Client) maskError(err error, extraCredentials ...string) error {
	if err == nil {
		return nil
	}
	raw := err.Error()
	msg := c.maskCredentialText(raw, extraCredentials...)
	if msg == raw {
		return err
	}
	return maskedError{msg: msg}
}

func (c *Client) maskCredentialText(text string, extraCredentials ...string) string {
	if text == "" {
		return text
	}
	type credentialMask struct {
		needle      string
		replacement string
	}
	var masks []credentialMask
	seen := map[string]struct{}{}
	addValue := func(value string) {
		value = strings.TrimSpace(value)
		if value == "" {
			return
		}
		replacement := maskToken(value)
		addMask := func(needle string) {
			if needle == "" {
				return
			}
			if _, ok := seen[needle]; ok {
				return
			}
			seen[needle] = struct{}{}
			masks = append(masks, credentialMask{needle: needle, replacement: replacement})
		}
		addMask(value)
		if escaped := url.QueryEscape(value); escaped != value {
			addMask(escaped)
		}
		if escaped := url.PathEscape(value); escaped != value {
			addMask(escaped)
		}
	}
	addCredential := func(value string) {
		value = strings.TrimSpace(value)
		addValue(value)
		if _, token, ok := strings.Cut(value, " "); ok {
			addValue(token)
		}
	}
	for _, value := range extraCredentials {
		addCredential(value)
	}
	if c != nil && c.Config != nil {
		addCredential(c.Config.AuthHeaderVal)
		addCredential(c.Config.AuthHeader())
		addCredential(c.Config.AccessToken)
		addCredential(c.Config.RefreshToken)
		addCredential(c.Config.ClientSecret)
		addCredential(c.Config.XBearerToken)
		addCredential(c.Config.XOauth2UserToken)
	}
	sort.SliceStable(masks, func(i, j int) bool {
		return len(masks[i].needle) > len(masks[j].needle)
	})
	masked := text
	for _, mask := range masks {
		masked = strings.ReplaceAll(masked, mask.needle, mask.replacement)
	}
	return masked
}

func truncateBody(b []byte) string {
	const maxBytes = 4096
	if len(b) <= maxBytes {
		return string(b)
	}
	return strings.ToValidUTF8(string(b[:maxBytes]), "") + "..."
}
